import React, { useState } from 'react';

export default function AddPost(props) {
    const [title, setTitle] = useState("")
    const [info, setInfo] = useState("")
    const [errMsg, setErrMsg] = useState("")

    const checkTitle = (event) => {
        let input = event.traget.value
        if (input >= 2) {
            setTitle(input)
            setErrMsg("")
        }
        else {
            setTitle('')
            setErrMsg("Title is too short")
        }
    }
    const checkInfo = (event) => {
        let input = event.traget.value
    }
    return (
        <div>
            <h4>Add new Post</h4>
            Title : <input id={"title"} onChange={checkTitle} type={"text"} /><br />
            Info : <input id={"info"} onChange={checkInfo} type={"text"} /><br />
            <button type='Submit' onClick={() => { props.newPost("title", "info") }}>Send</button>




        </div>

    )
}
